/*
 * Minimal html2canvas-compatible API
 * Uses SVG foreignObject approach to capture DOM as canvas.
 * Sets window.html2canvas(element, options) -> Promise<canvas>
 */
(function (global) {
  'use strict';

  global.html2canvas = function (element, options) {
    return new Promise(function (resolve) {
      var scale = (options && options.scale) || global.devicePixelRatio || 1;
      var canvas = document.createElement('canvas');
      var w = element.scrollWidth;
      var h = element.scrollHeight;
      canvas.width = w * scale;
      canvas.height = h * scale;
      var ctx = canvas.getContext('2d');

      // Scale context for DPR
      ctx.scale(scale, scale);

      // Serialize outerHTML — use a clone so we can expand collapsed elements
      var clone;
      try {
        clone = element.cloneNode(true);
      } catch (e) {
        resolve(canvas);
        return;
      }

      // Inline computed styles on clone to improve fidelity
      try {
        var allSrc = element.querySelectorAll('*');
        var allDst = clone.querySelectorAll('*');
        for (var i = 0; i < allSrc.length && i < allDst.length; i++) {
          var cs = global.getComputedStyle(allSrc[i]);
          allDst[i].setAttribute('style', cs.cssText);
        }
      } catch (e) {
        // ignore style inlining errors, proceed with raw HTML
      }

      var htmlContent;
      try {
        htmlContent = clone.outerHTML;
      } catch (e) {
        htmlContent = element.outerHTML;
      }

      var svgData =
        '<svg xmlns="http://www.w3.org/2000/svg" width="' + w + '" height="' + h + '">' +
        '<foreignObject width="100%" height="100%">' +
        '<div xmlns="http://www.w3.org/1999/xhtml" style="margin:0;padding:0;">' +
        htmlContent +
        '</div>' +
        '</foreignObject>' +
        '</svg>';

      var img = new Image();
      var svgBlob;
      var url;

      try {
        svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
        url = URL.createObjectURL(svgBlob);
      } catch (e) {
        // Blob/URL not supported — return blank canvas
        resolve(canvas);
        return;
      }

      img.onload = function () {
        try {
          ctx.drawImage(img, 0, 0);
        } catch (e) {
          // tainted canvas — leave blank
        }
        URL.revokeObjectURL(url);
        resolve(canvas);
      };

      img.onerror = function () {
        URL.revokeObjectURL(url);
        // Return blank canvas on error
        resolve(canvas);
      };

      img.src = url;
    });
  };

}(typeof window !== 'undefined' ? window : this));
